import React, { useState, useEffect } from 'react';
import { View, Text, TouchableOpacity, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import RNBiometrics from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [showLogin, setShowLogin] = useState(true);

  useEffect(() => {
    checkAuthStatus();
  }, []);

  const checkAuthStatus = async () => {
    try {
      const storedAuth = await AsyncStorage.getItem('isAuthenticated');
      if (storedAuth === 'true') {
        setIsAuthenticated(true);
        setShowLogin(false);
      }
    } catch (error) {
      console.log('Error checking auth status:', error);
    }
  };

  const authenticateBiometrics = async () => {
    try {
      const { available, biometryType } = await RNBiometrics.isSensorAvailable();
      
      if (available) {
        const { success, signature } = await RNBiometrics.simplePrompt({
          promptMessage: 'Authenticate to access the app'
        });

        if (success) {
          await AsyncStorage.setItem('isAuthenticated', 'true');
          setIsAuthenticated(true);
          setShowLogin(false);
          return true;
        }
      } else {
        // Fallback to password login
        return false;
      }
    } catch (error) {
      console.log('Biometric authentication error:', error);
      return false;
    }
    return false;
  };

  const handleLogin = async (password) => {
    // Simulate password validation
    if (password === '123456') {
      await AsyncStorage.setItem('isAuthenticated', 'true');
      setIsAuthenticated(true);
      setShowLogin(false);
    } else {
      Alert.alert('Error', 'Invalid password');
    }
  };

  const handleBiometricLogin = async () => {
    const success = await authenticateBiometrics();
    if (!success) {
      // Show password login screen
      setShowLogin(true);
    }
  };

  if (isAuthenticated) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <Text>Welcome to the App!</Text>
      </View>
    );
  }

  if (showLogin) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: 20 }}>
        <Text style={{ fontSize: 24, marginBottom: 20 }}>Login</Text>
        <TouchableOpacity 
          onPress={handleBiometricLogin}
          style={{ 
            backgroundColor: '#007AFF', 
            padding: 15, 
            borderRadius: 5, 
            marginBottom: 10,
            width: '80%'
          }}
        >
          <Text style={{ color: 'white', textAlign: 'center' }}>Use Biometrics</Text>
        </TouchableOpacity>
        <Text style={{ marginBottom: 10 }}>or</Text>
        <TouchableOpacity 
          onPress={() => setShowLogin(false)}
          style={{ 
            backgroundColor: '#3498db', 
            padding: 15, 
            borderRadius: 5,
            width: '80%'
          }}
        >
          <Text style={{ color: 'white', textAlign: 'center' }}>Enter Password</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: 20 }}>
      <Text style={{ fontSize: 24, marginBottom: 20 }}>Password Login</Text>
      <Text style={{ marginBottom: 10 }}>Enter your password:</Text>
      <TouchableOpacity 
        onPress={() => handleLogin('123456')}
        style={{ 
          backgroundColor: '#2ecc71', 
          padding: 15, 
          borderRadius: 5,
          width: '80%'
        }}
      >
        <Text style={{ color: 'white', textAlign: 'center' }}>Login</Text>
      </TouchableOpacity>
    </View>
  );
};

export default App;